# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, send_file
from selenium import webdriver
import boto3
import io
import urllib.request

app = Flask(__name__)
s3 = boto3.client('s3')

def save_to_s3(data, key):
    s3.put_object(Body=data, Bucket='bucket-name', Key=key)

def get_thumbnail(url):
    options = webdriver.ChromeOptions()
    options.add_argument('--headless')
    driver = webdriver.Chrome(options=options)
    driver.get(url)
    thumbnail = io.BytesIO()
    driver.save_screenshot(thumbnail)
    return thumbnail

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json.get('url')
    if not url:
        return 'URL is required.', 400
    try:
        thumbnail = get_thumbnail(url)
        key = f'screenshots/{urllib.parse.quote(url)}'
        save_to_s3(thumbnail.getvalue(), key)
        thumbnail.seek(0)
        return send_file(thumbnail, mimetype='image/jpeg')
    except Exception as e:
        print(f'Error generating screenshot: {e}')
        return 'Error generating screenshot.', 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=80)